import{_ as e,c as n,o as a,a as s}from"./app.80007782.js";const m=JSON.parse('{"title":"\u{1F680} UniTrack Deployment Overview","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u{1F3D7}\uFE0F System Architecture","slug":"\u{1F3D7}\uFE0F-system-architecture","link":"#\u{1F3D7}\uFE0F-system-architecture","children":[]},{"level":2,"title":"\u{1F4E6} Components Overview","slug":"\u{1F4E6}-components-overview","link":"#\u{1F4E6}-components-overview","children":[{"level":3,"title":"Database (PostgreSQL)","slug":"database-postgresql","link":"#database-postgresql","children":[]},{"level":3,"title":"Backend API (ASP.NET Core)","slug":"backend-api-asp-net-core","link":"#backend-api-asp-net-core","children":[]},{"level":3,"title":"Frontend (Nuxt.js)","slug":"frontend-nuxt-js","link":"#frontend-nuxt-js","children":[]},{"level":3,"title":"Load Balancer (NGINX)","slug":"load-balancer-nginx","link":"#load-balancer-nginx","children":[]},{"level":3,"title":"Monitoring Stack","slug":"monitoring-stack","link":"#monitoring-stack","children":[]}]},{"level":2,"title":"\u{1F504} Network Configuration","slug":"\u{1F504}-network-configuration","link":"#\u{1F504}-network-configuration","children":[]},{"level":2,"title":"\u{1F680} Deployment Process","slug":"\u{1F680}-deployment-process","link":"#\u{1F680}-deployment-process","children":[]},{"level":2,"title":"\u{1F6E0}\uFE0F Important Files","slug":"\u{1F6E0}\uFE0F-important-files","link":"#\u{1F6E0}\uFE0F-important-files","children":[]},{"level":2,"title":"\u2705 Prerequisites","slug":"\u2705-prerequisites","link":"#\u2705-prerequisites","children":[]}],"relativePath":"en/setup/getting-started.md","lastUpdated":1744659307000}'),i={name:"en/setup/getting-started.md"},t=s(`<h1 id="\u{1F680}-unitrack-deployment-overview" tabindex="-1">\u{1F680} UniTrack Deployment Overview <a class="header-anchor" href="#\u{1F680}-unitrack-deployment-overview" aria-hidden="true">#</a></h1><div class="deployment-banner"><div class="banner-content"><div class="banner-icon">\u{1F527}</div><h2>Understanding the UniTrack Infrastructure</h2></div></div><p>Welcome to the deployment guide for UniTrack! This page provides a quick overview of the various components that make up the UniTrack system and how they work together.</p><h2 id="\u{1F3D7}\uFE0F-system-architecture" tabindex="-1">\u{1F3D7}\uFE0F System Architecture <a class="header-anchor" href="#\u{1F3D7}\uFE0F-system-architecture" aria-hidden="true">#</a></h2><p>UniTrack is built using a modern containerized architecture, with several key components working together to provide a robust educational management platform.</p><div class="architecture-diagram"><div class="arch-component client"><span class="component-icon">\u{1F5A5}\uFE0F</span><span class="component-label">Client Browsers</span></div><div class="arch-arrow">\u25B6</div><div class="arch-component nginx"><span class="component-icon">\u{1F504}</span><span class="component-label">NGINX Load Balancer</span></div><div class="arch-arrow">\u25B6</div><div class="arch-component-group"><div class="arch-component frontend"><span class="component-icon">\u{1F3A8}</span><span class="component-label">Nuxt Frontend</span></div><div class="arch-component backend"><span class="component-icon">\u2699\uFE0F</span><span class="component-label">ASP.NET Backend (x2)</span></div></div><div class="arch-arrow">\u25B6</div><div class="arch-component database"><span class="component-icon">\u{1F418}</span><span class="component-label">PostgreSQL Database</span></div><div class="arch-monitoring"><div class="arch-component monitoring"><span class="component-icon">\u{1F4CA}</span><span class="component-label">Prometheus + Grafana</span></div></div></div><h2 id="\u{1F4E6}-components-overview" tabindex="-1">\u{1F4E6} Components Overview <a class="header-anchor" href="#\u{1F4E6}-components-overview" aria-hidden="true">#</a></h2><h3 id="database-postgresql" tabindex="-1">Database (PostgreSQL) <a class="header-anchor" href="#database-postgresql" aria-hidden="true">#</a></h3><ul><li><strong>Role</strong>: Stores all application data</li><li><strong>Configuration</strong>: Runs on port 5434 (mapped to internal 5432)</li><li><strong>Persistence</strong>: Uses Docker volumes for data persistence</li><li><strong>Health Checks</strong>: Automatically monitored for availability</li></ul><h3 id="backend-api-asp-net-core" tabindex="-1">Backend API (<a href="http://ASP.NET" target="_blank" rel="noreferrer">ASP.NET</a> Core) <a class="header-anchor" href="#backend-api-asp-net-core" aria-hidden="true">#</a></h3><ul><li><strong>Role</strong>: Provides the RESTful API services and business logic</li><li><strong>Scaling</strong>: Deployed with 2 replicas for high availability</li><li><strong>Dependencies</strong>: Requires the database and Firebase credentials</li><li><strong>Security</strong>: Uses secret management for sensitive configuration</li></ul><h3 id="frontend-nuxt-js" tabindex="-1">Frontend (Nuxt.js) <a class="header-anchor" href="#frontend-nuxt-js" aria-hidden="true">#</a></h3><ul><li><strong>Role</strong>: Delivers the user interface to browsers</li><li><strong>Configuration</strong>: Exposes port 3000</li><li><strong>API Integration</strong>: Configured to connect to the backend via NGINX</li></ul><h3 id="load-balancer-nginx" tabindex="-1">Load Balancer (NGINX) <a class="header-anchor" href="#load-balancer-nginx" aria-hidden="true">#</a></h3><ul><li><strong>Role</strong>: Routes traffic and provides SSL termination</li><li><strong>Configuration</strong>: Exposes ports 8080 (HTTPS) and 8081 (HTTP)</li><li><strong>SSL</strong>: Uses certificates stored in the ./ssl directory</li></ul><h3 id="monitoring-stack" tabindex="-1">Monitoring Stack <a class="header-anchor" href="#monitoring-stack" aria-hidden="true">#</a></h3><ul><li><strong>Prometheus</strong>: Collects metrics from the services</li><li><strong>Grafana</strong>: Provides visualization dashboards for monitoring</li><li><strong>Access</strong>: Grafana UI available on port 3001</li></ul><h2 id="\u{1F504}-network-configuration" tabindex="-1">\u{1F504} Network Configuration <a class="header-anchor" href="#\u{1F504}-network-configuration" aria-hidden="true">#</a></h2><p>All services are connected through the <code>app-network</code> overlay network, allowing secure communication between containers.</p><div class="note-box"><div class="note-icon">\u{1F4A1}</div><div class="note-content"><strong>Pro Tip:</strong> The overlay network type allows this setup to scale across multiple Docker hosts in a swarm if needed. </div></div><h2 id="\u{1F680}-deployment-process" tabindex="-1">\u{1F680} Deployment Process <a class="header-anchor" href="#\u{1F680}-deployment-process" aria-hidden="true">#</a></h2><p>Deploying the full stack is straightforward with Docker Compose:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># Build and deploy all services</span></span>
<span class="line"><span style="color:#A6ACCD;">docker-compose up -d</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># View logs for all services</span></span>
<span class="line"><span style="color:#A6ACCD;">docker-compose logs -f</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># Scale specific services if needed</span></span>
<span class="line"><span style="color:#A6ACCD;">docker-compose up -d --scale unitrack-backend=3</span></span>
<span class="line"></span></code></pre></div><h2 id="\u{1F6E0}\uFE0F-important-files" tabindex="-1">\u{1F6E0}\uFE0F Important Files <a class="header-anchor" href="#\u{1F6E0}\uFE0F-important-files" aria-hidden="true">#</a></h2><p>Make sure you have these files in your deployment directory:</p><div class="files-list"><div class="file"><span class="file-icon">\u{1F4C4}</span><span class="file-name">docker-compose.yml</span><span class="file-description">Main configuration file</span></div><div class="file"><span class="file-icon">\u{1F4C4}</span><span class="file-name">nginx.conf</span><span class="file-description">NGINX configuration</span></div><div class="file"><span class="file-icon">\u{1F4C4}</span><span class="file-name">prometheus.yml</span><span class="file-description">Prometheus configuration</span></div><div class="file"><span class="file-icon">\u{1F510}</span><span class="file-name">Firebase credentials</span><span class="file-description">For authentication</span></div></div><h2 id="\u2705-prerequisites" tabindex="-1">\u2705 Prerequisites <a class="header-anchor" href="#\u2705-prerequisites" aria-hidden="true">#</a></h2><p>Before deployment, ensure you have:</p><ul><li>Docker and Docker Compose installed</li><li>Network ports 3000, 3001, 5434, 8080, 8081, and 9090 available</li><li>SSL certificates (for production deployment)</li><li>Firebase project credentials file</li></ul><p>Ready to get started? Head over to our detailed <a href="./en/setup/deployment-dev.html">Docker Development Guide</a> or <a href="./en/setup/deployment-prod.html">Production Deployment Guide</a> for step-by-step instructions!</p>`,30),o=[t];function r(l,c,d,p,h,u){return a(),n("div",null,o)}const v=e(i,[["render",r]]);export{m as __pageData,v as default};
